     1→/**
     2→ * markdown-parser.js
     3→ * 외부 라이브러리 없이 구현한 마크다운 파서
     4→ *
     5→ * 지원 기능:
     6→ * - 제목 (h1~h6)
     7→ * - 굵게, 기울임, 굵은 기울임
     8→ * - 인라인 코드
     9→ * - 코드 블록 (언어 레이블 포함)
    10→ * - 링크, 이미지
    11→ * - 순서 없는/있는 목록 (중첩 포함)
    12→ * - 인용구 (중첩 포함)
    13→ * - 수평선
    14→ * - 문단, 줄바꿈
    15→ * - 이스케이프 문자
    16→ */
    17→
    18→const MarkdownParser = (() => {
    19→  // HTML 특수문자 이스케이프 (XSS 방지)
    20→  function escapeHtml(text) {
    21→    return text
    22→      .replace(/&/g, '&amp;')
    23→      .replace(/</g, '&lt;')
    24→      .replace(/>/g, '&gt;')
    25→      .replace(/"/g, '&quot;')
    26→      .replace(/'/g, '&#39;');
    27→  }
    28→
    29→  // 이스케이프된 마크다운 문자를 플레이스홀더로 변환
    30→  function protectEscapes(text) {
    31→    return text.replace(/\\([\\`*_{}[\]()#+\-.!~|])/g, (match, char) => {
    32→      return `\x00ESC${char.charCodeAt(0)}\x00`;
    33→    });
    34→  }
    35→
    36→  // 플레이스홀더를 실제 문자로 복원
    37→  function restoreEscapes(text) {
