    68→    // 굵게: **text** 또는 __text__
    69→    text = text.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    70→    text = text.replace(/__(.+?)__/g, '<strong>$1</strong>');
    71→
    72→    // 기울임: *text* 또는 _text_
    73→    text = text.replace(/\*([^*\n]+?)\*/g, '<em>$1</em>');
    74→    text = text.replace(/_([^_\n]+?)_/g, '<em>$1</em>');
    75→
    76→    // ~~취소선~~
    77→    text = text.replace(/~~(.+?)~~/g, '<del>$1</del>');
    78→
    79→    // 줄바꿈: 두 개 이상의 공백 + 줄바꿈 또는 백슬래시 + 줄바꿈
    80→    text = text.replace(/  +\n/g, '<br>\n');
