    84→    return text;
    85→  }
    86→
    87→  // 목록 파싱 (중첩 지원)
    88→  function parseList(lines, startIndex, baseIndent) {
    89→    let html = '';
    90→    let i = startIndex;
    91→    let listType = null;
    92→
    93→    while (i < lines.length) {
    94→      const line = lines[i];
