   252→  // 메인 파서
   253→  function parse(markdown) {
   254→    if (!markdown || markdown.trim() === '') {
   255→      return '';
   256→    }
   257→
   258→    const lines = markdown.split('\n');
   259→    let html = '';
   260→    let i = 0;
   261→    let paragraphLines = [];
   262→
   263→    // 누적된 문단 줄을 HTML로 변환
   264→    function flushParagraph() {
