   307→        flushParagraph();
   308→        const level = headingMatch[1].length;
   309→        const content = parseInline(headingMatch[2].trim());
   310→        html += `<h${level}>${content}</h${level}>\n`;
   311→        i++;
   312→        continue;
   313→      }
   314→
   315→      // 수평선 (---, ***, ___)
   316→      if (/^(?:[-*_]){3,}\s*$/.test(trimmed)) {
   317→        flushParagraph();
   318→        html += '<hr>\n';
   319→        i++;
   320→        continue;
   321→      }
   322→
   323→      // Setext 스타일 제목 (=== 또는 ---)
   324→      if (i + 1 < lines.length) {
   325→        const nextLine = lines[i + 1];
   326→        if (/^=+\s*$/.test(nextLine) && trimmed) {
   327→          flushParagraph();
   328→          html += `<h1>${parseInline(trimmed)}</h1>\n`;
   329→          i += 2;
   330→          continue;
   331→        }
   332→        if (/^-+\s*$/.test(nextLine) && trimmed && nextLine.length >= 2) {
   333→          flushParagraph();
   334→          html += `<h2>${parseInline(trimmed)}</h2>\n`;
   335→          i += 2;
   336→          continue;
   337→        }
   338→      }
   339→
   340→      // 인용구
   341→      if (/^> ?/.test(line)) {
   342→        flushParagraph();
   343→        const result = parseBlockquote(lines, i);
   344→        html += result.html + '\n';
   345→        i = result.nextIndex;
   346→        continue;
   347→      }
   348→
   349→      // 목록 (순서 없는/있는)
   350→      if (/^(\s*)([-*+]|\d+[.)]) /.test(line)) {
   351→        flushParagraph();
   352→        const baseIndent = line.match(/^(\s*)/)[1].length;
   353→        const result = parseList(lines, i, baseIndent);
   354→        html += result.html + '\n';
   355→        i = result.nextIndex;
   356→        continue;
   357→      }
   358→
   359→      // 일반 텍스트: 문단에 추가
   360→      paragraphLines.push(line);
   361→      i++;
   362→    }
   363→
