   445→        editor.value =
   446→          value.substring(0, lineStart) +
   447→          '> ' + content +
   448→          value.substring(actualEnd);
   449→
   450→        const newStart = lineStart + 2;
   451→        const newEnd = newStart + content.length;
   452→        editor.setSelectionRange(newStart, newEnd);
   453→      } else {
   454→        const selectedText = value.substring(start, end);
   455→        const lines = selectedText.split('\n');
   456→        const newText = lines.map(line => '> ' + line).join('\n');
   457→
   458→        editor.value = value.substring(0, start) + newText + value.substring(end);
   459→        editor.setSelectionRange(start, start + newText.length);
   460→      }
   461→
   462→      updatePreview();
   463→      scheduleAutoSave();
   464→    },
   465→
   466→    hr() {
   467→      editor.focus();
   468→      const start = editor.selectionStart;
   469→      const value = editor.value;
   470→
   471→      const lineStart = value.lastIndexOf('\n', start - 1) + 1;
   472→      const before = value.substring(0, lineStart);
   473→      const after = value.substring(start);
   474→
   475→      const needsBefore = before.length > 0 && !before.endsWith('\n');
   476→      const prefix = needsBefore ? '\n\n' : '';
   477→
   478→      const hrText = `${prefix}---\n\n`;
   479→      editor.value = before + hrText + after;
   480→
   481→      const newPos = lineStart + hrText.length;
   482→      editor.setSelectionRange(newPos, newPos);
   483→
   484→      updatePreview();
   485→      scheduleAutoSave();
   486→    },
   487→  };
   488→
   489→  // 커서 위치에 텍스트 삽입
   490→  function insertAtCursor(text) {
   491→    const start = editor.selectionStart;
   492→    const end = editor.selectionEnd;
   493→    const value = editor.value;
   494→
   495→    editor.value = value.substring(0, start) + text + value.substring(end);
   496→    const newPos = start + text.length;
   497→    editor.setSelectionRange(newPos, newPos);
