section('2. 파서 — 인라인 서식');

sub('굵게 (**/**)');
assertContains(parse('**bold**'),          '<strong>bold</strong>',         '** 굵게');
assertContains(parse('__bold__'),          '<strong>bold</strong>',         '__ 굵게');
