sub('굵은 기울임 (***/___)');
assertContains(parse('***bi***'),  '<strong><em>bi</em></strong>',  '*** 굵은 기울임');
assertContains(parse('___bi___'),  '<strong><em>bi</em></strong>',  '___ 굵은 기울임');

