section('3. 파서 — 링크 & 이미지');

sub('기본 링크');
assertContains(parse('[text](https://example.com)'),
  '<a href="https://example.com">text</a>', '기본 링크');
assertContains(parse('[text](https://x.com "title")'),
  'title="title"', '타이틀 있는 링크');

sub('XSS 방지');
