    return { html: `<blockquote>${innerHtml}</blockquote>`, nextIndex: i };
  }

  // 코드 블록 파싱
  function parseCodeBlock(lines, startIndex, lang) {
    let codeLines = [];
    let i = startIndex + 1;

    while (i < lines.length && !lines[i].startsWith('```')) {
      codeLines.push(lines[i]);
      i++;
    }

    const code = escapeHtml(codeLines.join('\n'));
    const langLabel = lang
      ? `<span class="code-lang-label">${escapeHtml(lang)}</span>`
      : '';
    const html = `<div class="code-block-wrapper">${langLabel}<pre><code>${code}</code></pre></div>`;

    return { html, nextIndex: i + 1 };
  }

  // 들여쓰기 코드 블록 파싱 (공백 4개 또는 탭)
  function parseIndentedCodeBlock(lines, startIndex) {
    let codeLines = [];
    let i = startIndex;

    while (i < lines.length && /^(    |\t)/.test(lines[i])) {
      codeLines.push(lines[i].replace(/^(    |\t)/, ''));
      i++;
    }

    const code = escapeHtml(codeLines.join('\n'));
    return { html: `<pre><code>${code}</code></pre>`, nextIndex: i };
  }

  // 메인 파서
  function parse(markdown) {
    if (!markdown || markdown.trim() === '') {
      return '';
    }

    const lines = markdown.split('\n');
    let html = '';
    let i = 0;
    let paragraphLines = [];

    // 누적된 문단 줄을 HTML로 변환
    function flushParagraph() {
      if (paragraphLines.length === 0) return;
      const content = paragraphLines.join('\n').trim();
      if (content) {
        html += `<p>${parseInline(content)}</p>\n`;
      }
      paragraphLines = [];
    }

    while (i < lines.length) {
      const line = lines[i];
      const trimmed = line.trim();

      // 빈 줄: 문단 구분
      if (trimmed === '') {
        flushParagraph();
        i++;
        continue;
      }

      // 코드 블록 (``` 또는 ~~~)
      const fencedCodeMatch = line.match(/^(`{3,}|~{3,})(\w+)?/);
      if (fencedCodeMatch) {
        flushParagraph();
        const lang = fencedCodeMatch[2] || '';
        const result = parseCodeBlock(lines, i, lang);
        html += result.html + '\n';
        i = result.nextIndex;
        continue;
      }

      // 들여쓰기 코드 블록
      if (/^(    |\t)/.test(line)) {
        flushParagraph();
        const result = parseIndentedCodeBlock(lines, i);
        html += result.html + '\n';
        i = result.nextIndex;
        continue;
      }

      // 제목 (ATX 스타일: # ~ ######)
      const headingMatch = line.match(/^(#{1,6})\s+(.+?)(?:\s+#+\s*)?$/);
      if (headingMatch) {
        flushParagraph();
        const level = headingMatch[1].length;
        const content = parseInline(headingMatch[2].trim());
        html += `<h${level}>${content}</h${level}>\n`;
        i++;
        continue;
      }

      // 수평선 (---, ***, ___)
      if (/^(?:[-*_]){3,}\s*$/.test(trimmed)) {
        flushParagraph();
        html += '<hr>\n';
        i++;
        continue;
      }

      // Setext 스타일 제목 (=== 또는 ---)
      if (i + 1 < lines.length) {
        const nextLine = lines[i + 1];
        if (/^=+\s*$/.test(nextLine) && trimmed) {
          flushParagraph();
          html += `<h1>${parseInline(trimmed)}</h1>\n`;
          i += 2;
          continue;
        }
        if (/^-+\s*$/.test(nextLine) && trimmed && nextLine.length >= 2) {
          flushParagraph();
          html += `<h2>${parseInline(trimmed)}</h2>\n`;
          i += 2;
          continue;
        }
      }

      // 인용구
      if (/^> ?/.test(line)) {
        flushParagraph();
        const result = parseBlockquote(lines, i);
        html += result.html + '\n';
        i = result.nextIndex;
        continue;
      }

      // 목록 (순서 없는/있는)
      if (/^(\s*)([-*+]|\d+[.)]) /.test(line)) {
        flushParagraph();
        const baseIndent = line.match(/^(\s*)/)[1].length;
        const result = parseList(lines, i, baseIndent);
        html += result.html + '\n';
        i = result.nextIndex;
        continue;
      }

      // 일반 텍스트: 문단에 추가
      paragraphLines.push(line);
      i++;
    }

    // 남은 문단 처리
    flushParagraph();

    return html;
  }

  return { parse };
})();

