        html += result.html + '\n';
        i = result.nextIndex;
        continue;
      }

      // 제목 (ATX 스타일: # ~ ######)
      const headingMatch = line.match(/^(#{1,6})\s+(.+?)(?:\s+#+\s*)?$/);
