        flushParagraph();
        const result = parseBlockquote(lines, i);
        html += result.html + '\n';
        i = result.nextIndex;
        continue;
      }

      // 목록 (순서 없는/있는)
      if (/^(\s*)([-*+]|\d+[.)]) /.test(line)) {
        flushParagraph();
        const baseIndent = line.match(/^(\s*)/)[1].length;
        const result = parseList(lines, i, baseIndent);
        html += result.html + '\n';
        i = result.nextIndex;
        continue;
      }

      // 일반 텍스트: 문단에 추가
      paragraphLines.push(line);
      i++;
    }

    // 남은 문단 처리
    flushParagraph();

    return html;
  }

  return { parse };
})();

