      const after = editor.value.substring(end);

      const needsBefore = before.length > 0 && !before.endsWith('\n\n');
      const prefix = needsBefore ? '\n\n' : '';
      const suffix = '\n\n';

      const block = `${prefix}\`\`\`\n${placeholder}\n\`\`\`${suffix}`;
