        const lineEnd = value.indexOf('\n', start);
        const actualEnd = lineEnd === -1 ? value.length : lineEnd;
        const currentLine = value.substring(lineStart, actualEnd);
        const content = currentLine.trim() || '인용 텍스트';

        editor.value =
          value.substring(0, lineStart) +
          '> ' + content +
          value.substring(actualEnd);

        const newStart = lineStart + 2;
        const newEnd = newStart + content.length;
        editor.setSelectionRange(newStart, newEnd);
      } else {
        const selectedText = value.substring(start, end);
        const lines = selectedText.split('\n');
        const newText = lines.map(line => '> ' + line).join('\n');

        editor.value = value.substring(0, start) + newText + value.substring(end);
        editor.setSelectionRange(start, start + newText.length);
      }

      updatePreview();
      scheduleAutoSave();
    },

    hr() {
      editor.focus();
      const start = editor.selectionStart;
      const value = editor.value;

      const lineStart = value.lastIndexOf('\n', start - 1) + 1;
      const before = value.substring(0, lineStart);
      const after = value.substring(start);

      const needsBefore = before.length > 0 && !before.endsWith('\n');
      const prefix = needsBefore ? '\n\n' : '';

      const hrText = `${prefix}---\n\n`;
      editor.value = before + hrText + after;

      const newPos = lineStart + hrText.length;
      editor.setSelectionRange(newPos, newPos);

      updatePreview();
      scheduleAutoSave();
    },
  };

  // 커서 위치에 텍스트 삽입
  function insertAtCursor(text) {
    const start = editor.selectionStart;
    const end = editor.selectionEnd;
    const value = editor.value;

    editor.value = value.substring(0, start) + text + value.substring(end);
    const newPos = start + text.length;
    editor.setSelectionRange(newPos, newPos);

    updatePreview();
    scheduleAutoSave();
  }

  // ============================
  // 툴바 버튼 이벤트 바인딩
  // ============================
  function bindToolbarButtons() {
    const buttons = document.querySelectorAll('.toolbar-btn[data-action]');
    buttons.forEach(btn => {
      const action = btn.dataset.action;
      if (toolbarActions[action]) {
        btn.addEventListener('click', () => {
          toolbarActions[action]();
        });
      }
    });
  }

  // ============================
  // 키보드 단축키
  // ============================
  function bindKeyboardShortcuts() {
    editor.addEventListener('keydown', (e) => {
      const isMac = navigator.platform.toUpperCase().indexOf('MAC') >= 0;
      const ctrlOrMeta = isMac ? e.metaKey : e.ctrlKey;

      if (!ctrlOrMeta) return;

      switch (e.key.toLowerCase()) {
        case 'b':
          e.preventDefault();
          toolbarActions.bold();
          break;

        case 'i':
          e.preventDefault();
          toolbarActions.italic();
          break;

        case 'k':
          e.preventDefault();
          toolbarActions.link();
          break;
      }
    });
  }

  // ============================
  // Tab 키 처리 (들여쓰기)
  // ============================
  function bindTabKey() {
    editor.addEventListener('keydown', (e) => {
      if (e.key !== 'Tab') return;
      e.preventDefault();

      const start = editor.selectionStart;
      const end = editor.selectionEnd;
      const value = editor.value;

      if (start === end) {
        // 단일 커서: 공백 2개 삽입
        editor.value = value.substring(0, start) + '  ' + value.substring(end);
        editor.setSelectionRange(start + 2, start + 2);
      } else {
        // 선택 영역: 각 줄에 들여쓰기 추가/제거
        const selectedText = value.substring(start, end);
        const lines = selectedText.split('\n');

        let newText;
        if (e.shiftKey) {
          // 내어쓰기
          newText = lines.map(line => line.startsWith('  ') ? line.substring(2) : line).join('\n');
        } else {
          // 들여쓰기
          newText = lines.map(line => '  ' + line).join('\n');
        }

        editor.value = value.substring(0, start) + newText + value.substring(end);
        editor.setSelectionRange(start, start + newText.length);
      }

      updatePreview();
      scheduleAutoSave();
    });
  }

  // ============================
  // 드래그 리사이저
  // ============================
  function bindResizer() {
    let isDragging = false;
    let startX = 0;
    let startEditorWidth = 0;
    let isVertical = false;

    resizer.addEventListener('mousedown', (e) => {
      e.preventDefault();
      isDragging = true;

      const containerRect = editorContainer.getBoundingClientRect();
      isVertical = window.innerWidth <= 768;

      if (isVertical) {
        startX = e.clientY;
        startEditorWidth = editorPane.getBoundingClientRect().height;
      } else {
        startX = e.clientX;
        startEditorWidth = editorPane.getBoundingClientRect().width;
      }

      resizer.classList.add('dragging');
      document.body.style.cursor = isVertical ? 'row-resize' : 'col-resize';
      document.body.style.userSelect = 'none';
    });

    document.addEventListener('mousemove', (e) => {
      if (!isDragging) return;

      const containerRect = editorContainer.getBoundingClientRect();

      if (isVertical) {
        const delta = e.clientY - startX;
        const containerHeight = containerRect.height;
        const newEditorHeight = startEditorWidth + delta;

        // 최소/최대 크기 제한 (20% ~ 80%)
        const minHeight = containerHeight * 0.2;
        const maxHeight = containerHeight * 0.8;
        const clampedHeight = Math.min(Math.max(newEditorHeight, minHeight), maxHeight);
        const percentage = (clampedHeight / containerHeight) * 100;

        editorPane.style.flex = 'none';
        editorPane.style.height = `${percentage}%`;
        previewPane.style.flex = '1';
        previewPane.style.height = '';
      } else {
        const delta = e.clientX - startX;
        const containerWidth = containerRect.width;
        const newEditorWidth = startEditorWidth + delta;

        // 최소/최대 크기 제한 (20% ~ 80%)
        const minWidth = containerWidth * 0.2;
        const maxWidth = containerWidth * 0.8;
        const clampedWidth = Math.min(Math.max(newEditorWidth, minWidth), maxWidth);
        const percentage = (clampedWidth / containerWidth) * 100;

        editorPane.style.flex = 'none';
        editorPane.style.width = `${percentage}%`;
        previewPane.style.flex = '1';
        previewPane.style.width = '';
      }
    });

    document.addEventListener('mouseup', () => {
      if (!isDragging) return;
      isDragging = false;
      resizer.classList.remove('dragging');
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    });

    // 터치 지원
    resizer.addEventListener('touchstart', (e) => {
      e.preventDefault();
      const touch = e.touches[0];
      isDragging = true;
      isVertical = window.innerWidth <= 768;

      if (isVertical) {
        startX = touch.clientY;
        startEditorWidth = editorPane.getBoundingClientRect().height;
      } else {
        startX = touch.clientX;
        startEditorWidth = editorPane.getBoundingClientRect().width;
      }

      resizer.classList.add('dragging');
    }, { passive: false });

    document.addEventListener('touchmove', (e) => {
      if (!isDragging) return;
      const touch = e.touches[0];
      const containerRect = editorContainer.getBoundingClientRect();

      if (isVertical) {
        const delta = touch.clientY - startX;
        const containerHeight = containerRect.height;
        const newEditorHeight = startEditorWidth + delta;
        const minHeight = containerHeight * 0.2;
        const maxHeight = containerHeight * 0.8;
        const clampedHeight = Math.min(Math.max(newEditorHeight, minHeight), maxHeight);
        const percentage = (clampedHeight / containerHeight) * 100;

        editorPane.style.flex = 'none';
        editorPane.style.height = `${percentage}%`;
        previewPane.style.flex = '1';
      } else {
        const delta = touch.clientX - startX;
        const containerWidth = containerRect.width;
        const newEditorWidth = startEditorWidth + delta;
        const minWidth = containerWidth * 0.2;
        const maxWidth = containerWidth * 0.8;
        const clampedWidth = Math.min(Math.max(newEditorWidth, minWidth), maxWidth);
        const percentage = (clampedWidth / containerWidth) * 100;

        editorPane.style.flex = 'none';
        editorPane.style.width = `${percentage}%`;
        previewPane.style.flex = '1';
      }
    }, { passive: true });

    document.addEventListener('touchend', () => {
      if (!isDragging) return;
      isDragging = false;
      resizer.classList.remove('dragging');
    });
  }

  // ============================
  // HTML 내보내기
  // ============================
  function exportHtml() {
    const markdownContent = editor.value;
    const renderedHtml = MarkdownParser.parse(markdownContent);

    const fullHtml = `<!DOCTYPE html>
<html lang="ko">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>마크다운 내보내기</title>
  <style>
    :root {
      --text-primary: #24292f;
      --text-secondary: #57606a;
      --text-link: #0969da;
      --bg-code: #f6f8fa;
      --border: #d0d7de;
    }

    @media (prefers-color-scheme: dark) {
      :root {
        --text-primary: #e6edf3;
        --text-secondary: #8b949e;
        --text-link: #58a6ff;
        --bg-code: #161b22;
        --border: #30363d;
      }
      body { background: #0d1117; }
    }

    body {
      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif;
      font-size: 16px;
      line-height: 1.6;
      color: var(--text-primary);
      max-width: 800px;
      margin: 0 auto;
      padding: 40px 20px;
    }

    h1, h2, h3, h4, h5, h6 {
      margin-top: 24px;
      margin-bottom: 12px;
      font-weight: 600;
      line-height: 1.25;
    }

    h1 { font-size: 2em; padding-bottom: 0.3em; border-bottom: 1px solid var(--border); }
    h2 { font-size: 1.5em; padding-bottom: 0.3em; border-bottom: 1px solid var(--border); }
    h3 { font-size: 1.25em; }

    p { margin-bottom: 16px; }

    a { color: var(--text-link); text-decoration: none; }
    a:hover { text-decoration: underline; }

    code {
      font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
      font-size: 0.875em;
      padding: 0.2em 0.4em;
      background: var(--bg-code);
      border-radius: 4px;
      border: 1px solid var(--border);
    }

    pre {
      padding: 16px;
      overflow: auto;
      background: var(--bg-code);
      border-radius: 6px;
      border: 1px solid var(--border);
      margin-bottom: 16px;
    }

    pre code {
      padding: 0;
      background: transparent;
      border: none;
      font-size: 0.875em;
    }

    blockquote {
      margin: 0 0 16px;
      padding: 0 16px;
      color: var(--text-secondary);
      border-left: 4px solid var(--border);
    }

    ul, ol { margin-bottom: 16px; padding-left: 2em; }
    li { margin-bottom: 4px; }

    hr { height: 1px; margin: 24px 0; background: var(--border); border: 0; }

    img { max-width: 100%; height: auto; border-radius: 6px; border: 1px solid var(--border); }

    .code-block-wrapper { position: relative; margin-bottom: 16px; }
    .code-block-wrapper pre { margin-bottom: 0; }
    .code-lang-label {
      position: absolute;
      top: 8px;
      right: 12px;
      font-size: 11px;
      color: var(--text-secondary);
      background: var(--bg-code);
      padding: 2px 8px;
      border-radius: 4px;
      border: 1px solid var(--border);
    }
  </style>
</head>
<body>
  <article class="markdown-body">
${renderedHtml}
  </article>
</body>
</html>`;

    // 파일 다운로드
    const blob = new Blob([fullHtml], { type: 'text/html;charset=utf-8' });
    const url = URL.createObjectURL(blob);

    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
    const filename = `markdown-export-${timestamp}.html`;

    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.style.display = 'none';
    document.body.appendChild(a);
    a.click();

    // 정리
    setTimeout(() => {
      URL.revokeObjectURL(url);
      document.body.removeChild(a);
    }, 100);
  }

  // ============================
  // 초기화
  // ============================
  function init() {
    // 저장된 내용 복원
    restoreFromLocalStorage();

    // 초기 미리보기 렌더링
    updatePreview();

    // 에디터 입력 이벤트
    editor.addEventListener('input', () => {
      updatePreview();
      scheduleAutoSave();
    });

    // 툴바 버튼 바인딩
    bindToolbarButtons();

    // 키보드 단축키
    bindKeyboardShortcuts();

    // Tab 키 처리
    bindTabKey();

    // 리사이저
    bindResizer();

    // HTML 내보내기
    exportBtn.addEventListener('click', exportHtml);

    // 창 크기 변경 시 반응형 처리
    window.addEventListener('resize', () => {
      // 가로/세로 전환 시 패널 크기 초기화
      if (window.innerWidth <= 768) {
        editorPane.style.flex = '';
        editorPane.style.width = '';
        editorPane.style.height = '';
        previewPane.style.flex = '';
        previewPane.style.width = '';
        previewPane.style.height = '';
      }
    });
  }

  // DOM 로드 완료 후 초기화
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();

