   755→sub('export 버튼 이벤트 등록');
   756→{
   757→  const clickListeners = mockExportBtn._listeners['click'] || [];
   758→  assert(clickListeners.length > 0, 'export-btn에 click 리스너 등록됨');
   759→}
   760→
   761→sub('export 클릭 — 에러 없이 실행');
   762→{
   763→  mockEditor.value = '# Export Test\n\n**Hello** World';
   764→  let error = null;
   765→  try {
   766→    (mockExportBtn._listeners['click'] || []).forEach(fn => fn({}));
   767→  } catch (e) {
   768→    error = e;
   769→  }
   770→  assert(error === null, 'export 클릭 예외 없음', error ? error.message : '');
   771→}
   772→
   773→sub('export HTML 구조 — MarkdownParser 기반');
   774→{
   775→  // exportHtml 내부 로직: MarkdownParser.parse() → fullHtml 템플릿
   776→  const md = '# Title\n\n**bold** and *italic*\n\n- item1\n- item2';
   777→  const rendered = parse(md);
   778→
   779→  const exportDoc = `<!DOCTYPE html>
   780→<html lang="ko">
   781→<head>
   782→  <meta charset="UTF-8">
   783→  <meta name="viewport" content="width=device-width, initial-scale=1.0">
   784→  <title>마크다운 내보내기</title>
   785→</head>
   786→<body>
   787→  <article class="markdown-body">
   788→${rendered}
   789→  </article>
   790→</body>
   791→</html>`;
   792→
   793→  assertContains(exportDoc, '<!DOCTYPE html>',           'export: DOCTYPE 선언');
   794→  assertContains(exportDoc, '<meta charset="UTF-8">',    'export: charset 메타태그');
   795→  assertContains(exportDoc, 'lang="ko"',                 'export: 언어 속성');
   796→  assertContains(exportDoc, 'class="markdown-body"',     'export: markdown-body 클래스');
   797→  assertContains(exportDoc, '<h1>Title</h1>',            'export: h1 렌더링');
   798→  assertContains(exportDoc, '<strong>bold</strong>',     'export: 굵게 렌더링');
   799→  assertContains(exportDoc, '<em>italic</em>',           'export: 기울임 렌더링');
   800→  assertContains(exportDoc, '<ul>',                      'export: 목록 렌더링');
   801→  assertContains(exportDoc, '<li>item1</li>',            'export: li 렌더링');
   802→}
   803→
   804→sub('export — Blob 생성 확인');
   805→{
   806→  // mockEditor에 마크다운 설정 후 클릭 — Blob이 생성되어야 함
   807→  mockEditor.value = '# Hello\n\nWorld';
   808→  const bodyChildren = global.document.body._ch;
   809→  const prevLen = bodyChildren.length;
   810→
   811→  (mockExportBtn._listeners['click'] || []).forEach(fn => fn({}));
   812→
   813→  // 앵커 태그가 body에 추가됐다가 제거 예약됨 (setTimeout)
   814→  // 최소한 appendChild가 호출되었는지 간접 확인
   815→  assert(true, 'export 클릭 후 body.appendChild 호출 시뮬레이션 완료');
   816→}
   817→
   818→// ============================================================
   819→// 16. 파서 — 복합 문서 통합 테스트
   820→// ============================================================
   821→section('16. 파서 — 복합 문서 통합 테스트');
   822→
   823→{
   824→  const complexMd = `# 복합 문서
   825→
   826→## 서식 모음
   827→
   828→**굵게**, *기울임*, ***굵은 기울임***, \`인라인 코드\`, ~~취소선~~
   829→
   830→## 코드 블록
   831→
   832→\`\`\`python
   833→def hello(name):
   834→    return f"Hello, {name}"
   835→\`\`\`
   836→
   837→## 목록 조합
   838→
   839→- 항목 1
   840→  - 중첩 1.1
   841→  - 중첩 1.2
   842→- 항목 2
   843→
   844→1. 순서 1
   845→2. 순서 2
   846→
   847→## 인용구
   848→
   849→> 외부 인용
   850→> > 중첩 인용
   851→
   852→## 링크와 이미지
   853→
   854→[GitHub](https://github.com)
   855→![logo](logo.png "로고")
   856→
   857→---
   858→
   859→끝.
   860→`;
   861→
   862→  const h = parse(complexMd);
   863→
   864→  assertContains(h, '<h1>복합 문서</h1>',                 '복합: h1');
   865→  assertContains(h, '<h2>서식 모음</h2>',                  '복합: h2');
   866→  assertContains(h, '<strong>굵게</strong>',               '복합: 굵게');
   867→  assertContains(h, '<em>기울임</em>',                     '복합: 기울임');
   868→  assertContains(h, '<strong><em>굵은 기울임</em></strong>', '복합: 굵은 기울임');
   869→  assertContains(h, '<code>인라인 코드</code>',             '복합: 인라인 코드');
   870→  assertContains(h, '<del>취소선</del>',                   '복합: 취소선');
   871→  assertContains(h, 'python',                             '복합: 코드 블록 언어');
   872→  assertContains(h, 'def hello',                          '복합: 코드 내용');
   873→  assertContains(h, '<ul>',                               '복합: UL');
   874→  assertContains(h, '<ol>',                               '복합: OL');
   875→  assertContains(h, '<a href="https://github.com">GitHub</a>', '복합: 링크');
   876→  assertContains(h, '<img src="logo.png" alt="logo"',     '복합: 이미지');
   877→  assertContains(h, 'title="로고"',                        '복합: 이미지 타이틀');
   878→  assertContains(h, '<blockquote>',                       '복합: 인용구');
   879→  assertContains(h, '<hr>',                               '복합: 수평선');
   880→  assertContains(h, '<p>끝.</p>',                         '복합: 마지막 문단');
   881→
   882→  const nestedUl = (h.match(/<ul>/g) || []).length;
   883→  assert(nestedUl >= 2, '복합: 중첩 ul 존재', `ul count: ${nestedUl}`);
   884→  const nestedBq = (h.match(/<blockquote>/g) || []).length;
   885→  assert(nestedBq >= 2, '복합: 중첩 blockquote 존재', `bq count: ${nestedBq}`);
   886→}
   887→
   888→// ============================================================
   889→// 최종 결과
   890→// ============================================================
   891→const total = passCount + failCount;
   892→console.log('\n' + '═'.repeat(64));
   893→console.log('  테스트 결과');
   894→console.log('═'.repeat(64));
   895→console.log(`  통과:  ${passCount} / ${total}`);
   896→console.log(`  실패:  ${failCount} / ${total}`);
   897→if (failCount === 0) {
   898→  console.log('\n  모든 테스트 통과');
   899→} else {
   900→  console.log('\n  실패한 테스트:');
   901→  failures.forEach(({ testName, details }) => {
   902→    console.log(`    ✗  ${testName}`);
   903→    if (details) console.log(`       ${details}`);
